import { useCallback, useRef } from 'react';

// Base64 encoded short notification sound (subtle "pop" sound)
const NOTIFICATION_SOUND_DATA = 'data:audio/mp3;base64,';

export function useNotificationSound() {
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const playSound = useCallback(() => {
    try {
      if (!audioRef.current) {
        audioRef.current = new Audio(NOTIFICATION_SOUND_DATA);
        audioRef.current.volume = 0.3; // Subtle volume
      }
      
      // Reset and play
      audioRef.current.currentTime = 0;
      audioRef.current.play().catch(() => {
        // Ignore errors if user hasn't interacted with page yet
      });
    } catch {
      // Ignore audio errors
    }
  }, []);

  return { playSound };
}
